import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as t}from"./app-5f454ac1.js";const p={},e=t(`<p>전역 변수의 무분별한 사용은 위험하다.<br> 전역 변수를 반드시 사용해야 할 이유를 찾지 못한다면 지역 변수를 사용해야 한다.<br> 이번 장에서는 전역 변수의 문제점과 전역 변수의 사용을 억제할 수 있는 방법을 살펴보자.</p><h2 id="_1-변수의-생명-주기" tabindex="-1"><a class="header-anchor" href="#_1-변수의-생명-주기" aria-hidden="true">#</a> 1. 변수의 생명 주기</h2><h3 id="_1-1-지역-변수의-생명-주기" tabindex="-1"><a class="header-anchor" href="#_1-1-지역-변수의-생명-주기" aria-hidden="true">#</a> 1.1. 지역 변수의 생명 주기</h3><p>변수는 선언에 의해 생성되고 할당을 통해 값을 갖는다. 그리고 언젠가 소멸한다.<br> 즉, 변수는 생물과 유사하게 생성되고 소멸되는 생명 주기(life cycle)이 있다.</p><p>변수에 생명 주기가 없다면 한번 선언된 변수는 프로그램을 종료하지 않는 한 영원히 메모리 공간을 점유하게 된다.</p><p>함수 내부에서 선언된 지역 변수는 함수가 호출되면 생성되고 함수가 종료하면 소멸한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token string">&quot;local&quot;</span><span class="token punctuation">;</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// local</span>
  <span class="token keyword">return</span> x<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>지역 변수 x는 foo 함수가 호출되기 이전까지는 생성되지 않는다. foo 함수를 호출하지 않으면 함수 내부의 변수 선언문이 실행되지 않기 때문이다.</p><p>위 예제에의 foo 함수를 호출하면 가장 먼저 x 변수가 선언되고 undefined로 초기화 된다. 그 후, 함수 몸체를 구성하는 문들이 순차 실행하고 x 변수에 값이 할당된다. 그리고 함수가 종료하면 x 변수도 소멸된다.</p><p>즉, <strong>지역 변수의 생명주기는 함수의 생명 주기와 일치한다.</strong></p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/b592d305-7a1d-47f9-99a3-23e7f66ea83f" alt="그림 14-1. 지역변수의 생명주기" tabindex="0" loading="lazy"><figcaption>그림 14-1. 지역변수의 생명주기</figcaption></figure><p>지역 변수가 함수보다 오래 생존하는 경우도 있다. 함수가 생성한 스코프는 렉시컬 환경이라 부르는 물리적인 실체가 있다고 했다. 따라서 변수는 자신이 등록된 스코프가 소멸(메모리 해제)될 때 까지 유효하다.</p><p>할당된 메모리 공간은 더 이상 참조하지 않을 때 가비지 콜렉터에 의해 해제되어 가용 메모리 풀에 반환된다.<br> 즉, 누군가 메모리 공간을 참조하고 있으면 해제되지 않고 확보한 상태로 남아있게 된다.</p><p>일반적으로 함수가 종료하면 함수가 생성한 스코프도 소멸한다. 하지만 누군가 스코프를 참조하고 있다면 스코프는 해제되지 않고 생존하게 된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token string">&quot;global&quot;</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ①</span>
  <span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token string">&quot;local&quot;</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// global</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>foo 함수 내부에 선언된 지역 변수 x는 ①의 시점에 이미 선언되었고 undefined로 초기화 되어있다.<br> 따라서 전역 변수 x를 참조하는 것이 아니라 지역 변수 x를 참조해 값을 출력한다.<br> 즉, 지역 변수는 함수 전체에서 유효하다.</p><p>이처럼 <strong>호이스팅은 스코프를 단위로 동작한다.</strong></p><h3 id="_1-2-전역-변수의-생명주기" tabindex="-1"><a class="header-anchor" href="#_1-2-전역-변수의-생명주기" aria-hidden="true">#</a> 1.2. 전역 변수의 생명주기</h3><p>전역 코드는 함수 호출과 같이 전역코드를 실행하는 특별한 진입점이 없고 코드가 로드되자마자 곧바로 실행된다.<br> 함수는 함수 몸체의 마지막 문 또는 반환문이 실행되면 종료한다.<br> 하지만 전역 코드에는 반환문을 사용할 수 없으므로 마지막 문이 실행되어 더 이상 실행할 문이 없을 때 종료한다.</p><p>var 키워드로 선언한 전역 변수는 전역 객체의 프로퍼티가 된다.<br> 이는 전역 변수의 생명주기가 전역 객체의 생명 주기와 일치한다는 것을 말한다.</p><div class="hint-container info"><p class="hint-container-title">전역 객체(global object)</p><p>전역 객체는 코드가 실행되기 이전 단계에서 자바스크립트 엔진에 의해 어떤 객체보다도 먼저 생성되는 특수한 객체다.</p><p>전역 객체는 클라이언트 사이드 환경(브라우저)에서는 <code>window</code>, 서버 사이드 환경(Node.js)에서는 <code>global</code> 객체를 의미한다.</p><p>전역 객체는 표준 빌트인 객체(Object, String, Number, Function, Array ...)와 환경에 따른 호스트 객체, 그리고 var 키워드로 선언한 전역 변수와 전역 함수를 프로퍼티로 갖는다.</p><p>전역 객체와 표준 빌트인 객체에 대해서는 21장 &quot;빌트인 객체&quot;에서 살펴보자.</p></div><p>따라서 브라우저 환경에서 var 키워드로 선언한 전역 변수는 웹페이지를 닫을 때 까지 유효하다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/04f08ff2-1ddf-4452-ac40-ef66a3bf41d0" alt="그림 14-2. 전역변수의 생명주기" tabindex="0" loading="lazy"><figcaption>그림 14-2. 전역변수의 생명주기</figcaption></figure><h2 id="_2-전역-변수의-문제점" tabindex="-1"><a class="header-anchor" href="#_2-전역-변수의-문제점" aria-hidden="true">#</a> 2. 전역 변수의 문제점</h2><h4 id="암묵적-결합" tabindex="-1"><a class="header-anchor" href="#암묵적-결합" aria-hidden="true">#</a> 암묵적 결합</h4><p>전역 변수를 선언한 의도는 전역, 즉 어디서든 참조하고 할당할 수 있는 변수를 사용하겠다는 것이다.<br> 이는 모든 코드가 전역 변수를 참조하고 변경할 수 있는 암묵적 결합을 허용하는 것이다.<br> 변수의 유효 범위가 크면 클수록 코드의 가독성은 나빠지고 의도치 않게 상태가 변경될 수 있다.</p><h4 id="긴-생명주기" tabindex="-1"><a class="header-anchor" href="#긴-생명주기" aria-hidden="true">#</a> 긴 생명주기</h4><p>전역 변수는 생명주기가 길다. 따라서 메모리 리소스도 오랜 기간 소비한다.<br> 또한 전역 변수의 상태를 변경할 수 있는 시간도 길고 기회도 많다.<br> 생명 주기가 긴 전역 변수는 변수 이름이 중복될 가능성이 있다.<br> 변수 이름이 중복되면 의도치 않은 재할당이 이뤄진다.</p><h4 id="스코프-체인-상에서-종점에-존재" tabindex="-1"><a class="header-anchor" href="#스코프-체인-상에서-종점에-존재" aria-hidden="true">#</a> 스코프 체인 상에서 종점에 존재</h4><p>전역 변수는 스코프 체인상 종점에 존재한다. 이는 변수를 검색할 때 전역 변수가 가장 마지막에 검색된다.<br> 즉, 전역 변수의 검색 속도가 가장 느리다.</p><h4 id="네임스페이스-오염" tabindex="-1"><a class="header-anchor" href="#네임스페이스-오염" aria-hidden="true">#</a> 네임스페이스 오염</h4><p>자바스크립트의 가장 큰 문제점 중 하나는 파일이 분리되어 있다 해도 하나의 전역 스코프를 공유한다는 것이다.<br> 따라서 다른 파일 내에서 동일한 이름으로 명명된 전역 변수나 함수가 같은 스코프 내에 존재할 경우 예상치 못한 결과를 가져올 수 있다.</p><h2 id="_3-전역-변수의-사용을-억제하는-방법" tabindex="-1"><a class="header-anchor" href="#_3-전역-변수의-사용을-억제하는-방법" aria-hidden="true">#</a> 3. 전역 변수의 사용을 억제하는 방법</h2><p>전역 변수를 반드시 사용해야 할 이유를 찾지 못한다면 지역 변수를 사용해야한다. 변수의 스코프는 좁을수록 좋다.<br> 무분별한 전역 변수의 남발은 억제해야한다. 전역 변수의 사용을 억제할 수 있는 방법을 살펴보자.</p><h3 id="_3-1-즉시-실행-함수" tabindex="-1"><a class="header-anchor" href="#_3-1-즉시-실행-함수" aria-hidden="true">#</a> 3.1. 즉시 실행 함수</h3><p>함수 정의와 동시에 호출되는 즉시 실행 함수는 단 한 번만 호출된다.<br> 모든 코드를 즉시 실행 함수로 감싸면 모든 변수는 즉시 실행 함수의 지역 변수가 된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> foo <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
  <span class="token comment">// ...</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-네임스페이스-객체" tabindex="-1"><a class="header-anchor" href="#_3-2-네임스페이스-객체" aria-hidden="true">#</a> 3.2. 네임스페이스 객체</h3><p>전역에 네임스페이스역할을 담당할 객체를 생성하고 프로퍼티로 추가하는 방법이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> <span class="token constant">MYAPP</span> <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token constant">MYAPP</span><span class="token punctuation">.</span>name <span class="token operator">=</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token constant">MYAPP</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Lee</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>네임스페이스 객체에 또 다른 네임스페이스 객체를 프로퍼티로 추가해서 계층적으로 구성할 수도 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> <span class="token constant">MYAPP</span> <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token constant">MYAPP</span><span class="token punctuation">.</span>person <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">address</span><span class="token operator">:</span> <span class="token string">&quot;Seoul&quot;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token constant">MYAPP</span><span class="token punctuation">.</span>person<span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Lee</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>네임스페이스를 분리해서 식별자 충돌을 방지하는 효과는 있으나 네임스페이스 객체 자체가 전역 변수에 할당되므로 그다지 유용해 보이지는 않는다.</p><h3 id="_3-3-모듈-패턴" tabindex="-1"><a class="header-anchor" href="#_3-3-모듈-패턴" aria-hidden="true">#</a> 3.3. 모듈 패턴</h3><ul><li>클래스를 모방해서 관련이 있는 변수와 함수를 모아 즉시 실행 함수로 감싸 하나의 모듈을 만든다.</li><li>자바스크립트의 강력한 기능인 클로저를 기반으로 동작한다.</li><li>전역 변수 억제는 물론 캡슐화까지 구현할 수 있다.</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> Counter <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// private 변수</span>
  <span class="token keyword">var</span> num <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>

  <span class="token comment">// 외부로 공개할 데이터나 메서드를 프로퍼티로 추가한 객체를 반환한다.</span>
  <span class="token keyword">return</span> <span class="token punctuation">{</span>
    <span class="token function">increase</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">return</span> <span class="token operator">++</span>num<span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token function">decrease</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">return</span> <span class="token operator">--</span>num<span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// private 변수는 외부로 노출되지 않는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Counter<span class="token punctuation">.</span>num<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Counter<span class="token punctuation">.</span><span class="token function">increase</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Counter<span class="token punctuation">.</span><span class="token function">increase</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 2</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Counter<span class="token punctuation">.</span><span class="token function">decrease</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Counter<span class="token punctuation">.</span><span class="token function">decrease</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 0</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 예제의 즉시 실행 함수는 객체를 반환한다. 이 객체에는 외부에 노출하고 싶은 변수나 함수를 담아 반환한다.<br> 이때 반환되는 객체의 프로퍼티는 외부에 노출되는 퍼블릭 멤버다.<br> 외부로 노출하고 싶지 않은 변수나 함수는 반환하는 객체에 추가하지 않으면 외부에서 접근할 수 없는 프라이빗 멤버가 된다.</p><p>이에 대해서는 24장 &quot;클로저&quot;에서 자세히 살펴보기로 하자.</p><h3 id="_3-4-es6-모듈" tabindex="-1"><a class="header-anchor" href="#_3-4-es6-모듈" aria-hidden="true">#</a> 3.4. ES6 모듈</h3><p>ES6 모듈을 사용하면 더는 전역 변수를 사용할 수 없다.<br> ES6 모듈은 파일 자체의 독자적인 모듈 스코프를 제공한다.</p><p>모던 브라우저에서는 ES6 모듈을 사용할 수 있다. script 태그에 <code>type=&quot;module&quot;</code> 어트리뷰트를 추가하면 로드된 자바스크립트 파일은 모듈로서 동작한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token operator">&lt;</span>script type<span class="token operator">=</span><span class="token string">&quot;module&quot;</span> src<span class="token operator">=</span><span class="token string">&quot;lib.mjs&quot;</span><span class="token operator">&gt;</span><span class="token operator">&lt;</span><span class="token operator">/</span>script<span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>script type<span class="token operator">=</span><span class="token string">&quot;module&quot;</span> src<span class="token operator">=</span><span class="token string">&quot;app.mjs&quot;</span><span class="token operator">&gt;</span><span class="token operator">&lt;</span><span class="token operator">/</span>script<span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>ES6 모듈은 구형 브라우저에서는 동작하지 않으며, 사용하더라도 트랜스파일링이나 번들링이 필요하기 때문에 ES6 모듈 기능보다는 Webpack 등의 모듈 번들러를 사용하는 것이 일반적이다.</p>`,53),o=[e];function c(i,l){return s(),a("div",null,o)}const d=n(p,[["render",c],["__file","deepdive14.html.vue"]]);export{d as default};
